//\n//  AppState.swift\n//  PawRoutine\n//\n//  Created by Adward on 2026/4/24.\n//\n\nimport Foundation\nimport SwiftUI\n\n@Observable\nclass AppState {\n    var isLoading = false\n    var errorMessage: String?\n    var showError = false\n    \n    func setLoading(_ loading: Bool) {\n        isLoading = loading\n    }\n    \n    func setError(_ message: String) {\n        errorMessage = message\n        showError = true\n    }\n    \n    func clearError() {\n        errorMessage = nil\n        showError = false\n    }\n}\n\n// MARK: - Error Types\nenum AppError: LocalizedError {\n    case dataNotFound\n    case saveFailed\n    case deleteFailed\n    case exportFailed\n    case importFailed\n    case networkError\n    case unknownError\n    \n    var errorDescription: String? {\n        switch self {\n        case .dataNotFound:\n            return \"数据未找到\"\n        case .saveFailed:\n            return \"保存失败\"\n        case .deleteFailed:\n            return \"删除失败\"\n        case .exportFailed:\n            return \"导出失败\"\n        case .importFailed:\n            return \"导入失败\"\n        case .networkError:\n            return \"网络错误\"\n        case .unknownError:\n            return \"未知错误\"\n        }\n    }\n}\n\n// MARK: - Loading View\nstruct LoadingView: View {\n    let message: String\n    \n    var body: some View {\n        VStack(spacing: 16) {\n            ProgressView()\n                .scaleEffect(1.2)\n            \n            Text(message)\n                .font(.subheadline)\n                .foregroundColor(.secondary)\n        }\n        .frame(maxWidth: .infinity, maxHeight: .infinity)\n        .background(Color.black.opacity(0.3))\n        .ignoresSafeArea()\n    }\n}\n\n// MARK: - Empty State View\nstruct EmptyStateView: View {\n    let icon: String\n    let title: String\n    let message: String\n    let actionTitle: String?\n    let action: (() -> Void)?\n    \n    init(\n        icon: String,\n        title: String,\n        message: String,\n        actionTitle: String? = nil,\n        action: (() -> Void)? = nil\n    ) {\n        self.icon = icon\n        self.title = title\n        self.message = message\n        self.actionTitle = actionTitle\n        self.action = action\n    }\n    \n    var body: some View {\n        VStack(spacing: 20) {\n            Image(systemName: icon)\n                .font(.system(size: 60))\n                .foregroundColor(.gray)\n            \n            Text(title)\n                .font(.title2)\n                .fontWeight(.medium)\n            \n            Text(message)\n                .font(.body)\n                .foregroundColor(.secondary)\n                .multilineTextAlignment(.center)\n                .padding(.horizontal)\n            \n            if let actionTitle = actionTitle, let action = action {\n                Button(actionTitle, action: action)\n                    .buttonStyle(.borderedProminent)\n            }\n        }\n        .padding(.vertical, 40)\n    }\n}"}